// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import { Paper, Typography, Grid, Card, CardContent, IconButton, Table, TableHead, TableBody, TableRow, TableCell, Button } from "@mui/material";
import PeopleIcon from "@mui/icons-material/People";
import PersonIcon from "@mui/icons-material/Person";
import VerifiedUserIcon from "@mui/icons-material/VerifiedUser";
import PendingActionsIcon from "@mui/icons-material/PendingActions";
import DirectionsCarIcon from "@mui/icons-material/DirectionsCar";
import LogoutIcon from "@mui/icons-material/Logout";

import { getOverview, getUsers, getRiders, getApprovedCaptains, getPendingCaptains, getRides } from "../../services/adminApi";

export default function AdminDashboard({ logout }) {
  const [overview, setOverview] = useState({});
  const [activeTable, setActiveTable] = useState(null);
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);

  // Fetch overview counts
  useEffect(() => {
    async function fetchOverview() {
      try {
        const res = await getOverview();
        if (res.data.success) {
          setOverview(res.data);
        }
      } catch (err) {
        console.error("Overview fetch error:", err);
      }
    }
    fetchOverview();
  }, []);

  // Fetch table data dynamically based on clicked card
  const handleCardClick = async (type) => {
    setActiveTable(type);
    setLoading(true);
    try {
      let res;
      switch (type) {
        case "users":
          res = await getUsers();
          setData(res.data.users || []);
          break;
        case "riders":
          res = await getRiders();
          setData(res.data.riders || []);
          break;
        case "approvedCaptains":
          res = await getApprovedCaptains();
          setData(res.data.captains || []);
          break;
        case "pendingCaptains":
          res = await getPendingCaptains();
          setData(res.data.pendingCaptains || []);
          break;
        case "rides":
          res = await getRides();
          setData(res.data.rides || []);
          break;
        default:
          setData([]);
      }
    } catch (err) {
      console.error("Table fetch error:", err);
      setData([]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      <Grid container justifyContent="space-between" alignItems="center" sx={{ mb: 2 }}>
        <Typography variant="h4">Admin Dashboard</Typography>
        <Button variant="contained" color="error" startIcon={<LogoutIcon />} onClick={logout}>
          Logout
        </Button>
      </Grid>

      <Grid container spacing={2} sx={{ mb: 3 }}>
        <Grid item xs={12} sm={6} md={2}>
          <Card onClick={() => handleCardClick("users")} sx={{ cursor: "pointer" }}>
            <CardContent>
              <PeopleIcon fontSize="large" color="primary" />
              <Typography variant="h6">Users</Typography>
              <Typography variant="h5">{overview.users || 0}</Typography>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={2}>
          <Card onClick={() => handleCardClick("riders")} sx={{ cursor: "pointer" }}>
            <CardContent>
              <PersonIcon fontSize="large" color="secondary" />
              <Typography variant="h6">Riders</Typography>
              <Typography variant="h5">{overview.riders || 0}</Typography>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={2}>
          <Card onClick={() => handleCardClick("approvedCaptains")} sx={{ cursor: "pointer" }}>
            <CardContent>
              <VerifiedUserIcon fontSize="large" color="success" />
              <Typography variant="h6">Approved Captains</Typography>
              <Typography variant="h5">{overview.captains || 0}</Typography>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={2}>
          <Card onClick={() => handleCardClick("pendingCaptains")} sx={{ cursor: "pointer" }}>
            <CardContent>
              <PendingActionsIcon fontSize="large" color="warning" />
              <Typography variant="h6">Pending Captains</Typography>
              <Typography variant="h5">{overview.pendingCaptains || 0}</Typography>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={2}>
          <Card onClick={() => handleCardClick("rides")} sx={{ cursor: "pointer" }}>
            <CardContent>
              <DirectionsCarIcon fontSize="large" color="info" />
              <Typography variant="h6">Total Rides</Typography>
              <Typography variant="h5">{overview.rides || 0}</Typography>
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      <Paper sx={{ p: 2 }}>
        {loading ? (
          <Typography>Loading...</Typography>
        ) : data.length === 0 ? (
          <Typography>No data found.</Typography>
        ) : (
          <Table>
            <TableHead>
              <TableRow>
                {activeTable === "rides" ? (
                  <>
                    <TableCell>Rider</TableCell>
                    <TableCell>Captain</TableCell>
                    <TableCell>Pickup</TableCell>
                    <TableCell>Drop</TableCell>
                    <TableCell>Fare</TableCell>
                    <TableCell>Status</TableCell>
                  </>
                ) : (
                  <>
                    <TableCell>Name</TableCell>
                    <TableCell>Email</TableCell>
                    <TableCell>Mobile</TableCell>
                    <TableCell>Role</TableCell>
                    <TableCell>Login Count</TableCell>
                    <TableCell>Approval Status</TableCell>
                  </>
                )}
              </TableRow>
            </TableHead>
            <TableBody>
              {data.map((item) => (
                <TableRow key={item._id}>
                  {activeTable === "rides" ? (
                    <>
                      <TableCell>{item.riderId?.fullName || "-"}</TableCell>
                      <TableCell>{item.captainId?.fullName || "-"}</TableCell>
                      <TableCell>{item.pickup}</TableCell>
                      <TableCell>{item.drop}</TableCell>
                      <TableCell>{item.fare}</TableCell>
                      <TableCell>{item.status}</TableCell>
                    </>
                  ) : (
                    <>
                      <TableCell>{item.fullName}</TableCell>
                      <TableCell>{item.email}</TableCell>
                      <TableCell>{item.mobile}</TableCell>
                      <TableCell>{item.role}</TableCell>
                      <TableCell>{item.loginCount}</TableCell>
                      <TableCell>{item.approvalStatus}</TableCell>
                    </>
                  )}
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}
      </Paper>
    </div>
  );
}
